// Callback: job_id, status, error, pdf_transcript_base64, pdf_explanation_base64.
const item = $input.first();
const j = item.json || {};
const body = j.body || j.params || j;
const job_id = String(body.job_id ?? j.job_id ?? '');
const status = String(body.status ?? j.status ?? 'unknown');
const error = String(body.error ?? j.error ?? '');
const out = { json: { job_id, status, error } };
if (body.pdf_transcript_base64 ?? j.pdf_transcript_base64) out.json.pdf_transcript_base64 = body.pdf_transcript_base64 ?? j.pdf_transcript_base64;
if (body.pdf_explanation_base64 ?? j.pdf_explanation_base64) out.json.pdf_explanation_base64 = body.pdf_explanation_base64 ?? j.pdf_explanation_base64;
if (item.binary && Object.keys(item.binary).length) out.binary = item.binary;
return [out];

// Decode pdf_transcript_base64 and pdf_explanation_base64 into binary 'transcript' and 'explanation'.
const item = $input.first();
const json = item.json || {};
const bin = {};
const add = (key, b64, fileName) => {
  if (!b64) return;
  try {
    const buffer = Buffer.from(b64, 'base64');
    bin[key] = await this.helpers.prepareBinaryData(buffer, fileName);
  } catch (e) {
    bin[key] = { data: b64, mimeType: 'application/pdf', fileName };
  }
};
add('transcript', json.pdf_transcript_base64, 'lecture_transcript.pdf');
add('explanation', json.pdf_explanation_base64, 'lecture_explanation.pdf');
if (Object.keys(bin).length) return [{ json, binary: bin }];
return [item];
